logging.basicConfig(level=os.getenv("LOG_LEVEL", "INFO"))
logger = logging.getLogger("screenshot-service")

app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
S3_PUBLIC_BASE_URL = os.getenv("S3_PUBLIC_BASE_URL", "")
AWS_S3_ACL = os.getenv("AWS_S3_ACL", "")
CHROME_BINARY = os.getenv("CHROME_BINARY", "/usr/bin/google-chrome")
CHROMEDRIVER_PATH = os.getenv("CHROMEDRIVER_PATH", "/usr/bin/chromedriver")
PAGELOAD_TIMEOUT = int(os.getenv("PAGELOAD_TIMEOUT", "30"))
SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMBNAIL_WIDTH = int(os.getenv("THUMBNAIL_WIDTH", "600"))
THUMBNAIL_HEIGHT = int(os.getenv("THUMBNAIL_HEIGHT", "315"))
WAIT_AFTER_LOAD = float(os.getenv("WAIT_AFTER_LOAD", "2.0"))
MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))
USER_AGENT = os.getenv(
    "USER_AGENT",
    "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36 ScreenshotService/1.0",
)
ALLOWED_SCHEMES = {"http", "https"}
BLOCK_PRIVATE_IPS = os.getenv("BLOCK_PRIVATE_IPS", "true").lower() == "true"

s3 = boto3.client("s3", region_name=AWS_REGION)

PRIVATE_HOST_PATTERNS = [
    re.compile(r"^localhost$", re.I),
    re.compile(r"^127\.", re.I),
    re.compile(r"^10\.", re.I),
    re.compile(r"^192\.168\.", re.I),
    re.compile(r"^172\.(1[6-9]|2\d|3[0-1])\.", re.I),
    re.compile(r"^169\.254\.", re.I),
    re.compile(r"^\[::1\]$", re.I),
]

def validate_url(url: str) -> str:
    if not url or not isinstance(url, str):
        raise ValueError("url is required")
    url = url.strip()
    if len(url) > MAX_URL_LENGTH:
        raise ValueError("url too long")
    parsed = urlparse(url)
    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError("only http and https URLs are allowed")
    if not parsed.netloc:
        raise ValueError("invalid URL")
    host = parsed.hostname or ""
    if BLOCK_PRIVATE_IPS:
        for pattern in PRIVATE_HOST_PATTERNS:
            if pattern.match(host):
                raise ValueError("private or local addresses are not allowed")
    return url

def normalize_url(url: str) -> str:
    return url.strip()

def url_hash(url: str) -> str:
    return hashlib.sha256(url.encode("utf-8")).hexdigest()

def build_s3_key(url: str) -> str:
    digest = url_hash(url)
    return f"{S3_PREFIX}/{digest[:2]}/{digest[2:4]}/{digest}.jpg"

def build_public_url(bucket: str, key: str) -> str:
    if S3_PUBLIC_BASE_URL:
        return f"{S3_PUBLIC_BASE_URL.rstrip('/')}/{key}"
    return f"https://{bucket}.s3.{AWS_REGION}.amazonaws.com/{key}"

def create_driver():
    options = Options()
    options.binary_location = CHROME_BINARY
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--window-size=%d,%d" % (SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
    options.add_argument(f"--user-agent={USER_AGENT}")
    options.add_argument("--disable-blink-features=AutomationControlled")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--ignore-certificate-errors")
    service = ChromeService(executable_path=CHROMEDRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(PAGELOAD_TIMEOUT)
    return driver

def capture_screenshot(url: str) -> bytes:
    driver = None
    try:
        driver = create_driver()
        driver.get(url)
        time.sleep(WAIT_AFTER_LOAD)
        png = driver.get_screenshot_as_png()
        return png
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass

def make_thumbnail(image_bytes: bytes) -> bytes:
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        src_w, src_h = img.size
        target_ratio = THUMBNAIL_WIDTH / THUMBNAIL_HEIGHT
        src_ratio = src_w / src_h

        if src_ratio > target_ratio:
            new_w = int(src_h * target_ratio)
            left = (src_w - new_w) // 2
            box = (left, 0, left + new_w, src_h)
        else:
            new_h = int(src_w / target_ratio)
            top = (src_h - new_h) // 2
            box = (0, top, src_w, top + new_h)

        img = img.crop(box)
        img = img.resize((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.Resampling.LANCZOS)

        out = io.BytesIO()
        img.save(out, format="JPEG", quality=85, optimize=True)
        return out.getvalue()

def upload_to_s3(data: bytes, key: str, content_type: str = "image/jpeg"):
    extra_args = {
        "ContentType": content_type,
        "CacheControl": "public, max-age=31536000, immutable",
    }
    if AWS_S3_ACL:
        extra_args["ACL"] = AWS_S3_ACL

    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=data,
        **extra_args,
    )

def head_request(url: str, timeout: int = 10):
    try:
        return requests.head(url, allow_redirects=True, timeout=timeout)
    except Exception:
        return None

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"ok": True})

@app.route("/screenshot", methods=["POST"])
def screenshot():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    payload = request.get_json(silent=True) or {}
    url = payload.get("url")

    try:
        url = validate_url(normalize_url(url))
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    key = build_s3_key(url)
    public_url = build_public_url(S3_BUCKET, key)

    existing = head_request(public_url)
    if existing and existing.status_code == 200:
        return jsonify({
            "url": url,
            "s3_key": key,
            "image_url": public_url,
            "cached": True,
            "width": THUMBNAIL_WIDTH,
            "height": THUMBNAIL_HEIGHT,
        })

    try:
        raw_png = capture_screenshot(url)
        thumbnail_jpg = make_thumbnail(raw_png)
        upload_to_s3(thumbnail_jpg, key, "image/jpeg")
    except (BotoCoreError, ClientError) as e:
        logger.exception("S3 upload failed")
        return jsonify({"error": "failed to upload screenshot", "details": str(e)}), 500
    except Exception as e:
        logger.exception("Screenshot generation failed")
        return jsonify({"error": "failed to generate screenshot", "details": str(e)}), 500

    return jsonify({
        "url": url,
        "s3_key": key,
        "image_url": public_url,
        "cached": False,
        "width": THUMBNAIL_WIDTH,
        "height": THUMBNAIL_HEIGHT,
    })

@app.route("/screenshot", methods=["GET"])
def screenshot_get():
    url = request.args.get("url", "")
    with app.test_request_context(
        "/screenshot",
        method="POST",
        json={"url": url},
    ):
        return screenshot()

